I'm seeing behaviour from `py::array` that I don't understand w.r.t. numpy array reference counts.  Here's the test code:

#### reltest.cpp:
```C++
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>

namespace py = pybind11;

template <int I> class A {};

namespace pybind11 { namespace detail {
template<> class type_caster<A<0>> {
public:
    PYBIND11_TYPE_CASTER(A<0>, _(""));

    bool load(handle, bool) { return true; }

    static handle cast(A<0> src, return_value_policy, handle) {
        py::array_t<double> a({3, 3});
        return a.release();
    }
};
template<> class type_caster<A<1>> {
public:
    PYBIND11_TYPE_CASTER(A<1>, _(""));

    bool load(handle, bool) { return true; }

    static handle cast(A<1> src, return_value_policy, handle) {
        py::dict d;
        return d.release();
    }
};
}}

PYBIND11_PLUGIN(reltest) {
    py::module m("reltest");
    m.def("a0", []() -> A<0> { return A<0>(); });
    m.def("a1", []() -> A<1> { return A<1>(); });
    return m.ptr();
}
```

